import{_ as t,o,c as a,al as i}from"./chunks/framework.3KaqW_hl.js";const g=JSON.parse('{"title":"Create a DIY Boks User Tag","description":"","frontmatter":{},"headers":[],"relativePath":"guide/create_user_tag.md","filePath":"guide/create_user_tag.md"}'),r={name:"guide/create_user_tag.md"};function s(l,e,n,c,h,d){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="create-a-diy-boks-user-tag" tabindex="-1">Create a DIY Boks User Tag <a class="header-anchor" href="#create-a-diy-boks-user-tag" aria-label="Permalink to &quot;Create a DIY Boks User Tag&quot;">​</a></h1><p>This guide explains how to transform a standard NFC tag into a &quot;User Tag&quot; compatible with your Boks, allowing you to open the door via the NFC reader.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ol><li><strong>A Blank NFC Tag:</strong><ul><li>Type: <strong>Mifare Classic 1K</strong> (4-byte UID).</li><li><em>Note:</em> No need for a &quot;Magic&quot; tag (changeable UID) unless you want to clone an existing tag. A standard Mifare tag costs around $1/1€.</li></ul></li><li><strong>An Android Smartphone with NFC.</strong></li><li><strong>The App:</strong> <a href="https://play.google.com/store/apps/details?id=de.syss.MifareClassicTool" target="_blank" rel="noreferrer">Mifare Classic Tool (MCT)</a>.</li></ol><hr><h2 id="the-technique" tabindex="-1">The Technique <a class="header-anchor" href="#the-technique" aria-label="Permalink to &quot;The Technique&quot;">​</a></h2><p>The Boks doesn&#39;t read just any tag. To be detected, the tag must have a <strong>specific key</strong> on its <strong>Sector 1</strong>. Without this key, the Boks will ignore the tag.</p><ul><li><strong>Key A (Sector 1):</strong> <code>873D9EF6C1A0</code></li></ul><hr><h2 id="step-by-step-procedure-with-mct" tabindex="-1">Step-by-Step Procedure (with MCT) <a class="header-anchor" href="#step-by-step-procedure-with-mct" aria-label="Permalink to &quot;Step-by-Step Procedure (with MCT)&quot;">​</a></h2><h3 id="step-1-add-the-key-to-mct" tabindex="-1">Step 1: Add the Key to MCT <a class="header-anchor" href="#step-1-add-the-key-to-mct" aria-label="Permalink to &quot;Step 1: Add the Key to MCT&quot;">​</a></h3><ol><li>Launch <strong>Mifare Classic Tool</strong>.</li><li>Go to <strong>&quot;Edit/Analyze Key File&quot;</strong>.</li><li>Open the <code>std.keys</code> file (or create a new one).</li><li>Add a new line with the following key: <code>873D9EF6C1A0</code></li><li>Press the <strong>Floppy Disk</strong> icon to save.</li></ol><h3 id="step-2-write-the-key-to-the-tag" tabindex="-1">Step 2: Write the Key to the Tag <a class="header-anchor" href="#step-2-write-the-key-to-the-tag" aria-label="Permalink to &quot;Step 2: Write the Key to the Tag&quot;">​</a></h3><ol><li>Return to the main menu and choose <strong>&quot;Write Tag&quot;</strong>.</li><li>Select the <strong>&quot;Write Block&quot;</strong> mode.</li><li>In the <strong>Block Number</strong> field, enter: <strong><code>7</code></strong>. <ul><li><em>Why 7?</em> This is the last block of Sector 1, which contains the access keys.</li></ul></li><li>In the <strong>Data (Hex)</strong> field, copy-paste exactly this: <code>873D9EF6C1A07F078840FFFFFFFFFFFF</code><ul><li><code>873D9EF6C1A0</code>: Key A (User Scan).</li><li><code>7F078840</code>: Permissions (Access Bits).</li><li><code>FFFFFFFFFFFF</code>: Key B (Default).</li></ul></li><li>Place your blank tag on the back of your phone.</li><li>Press <strong>&quot;Write Block&quot;</strong>.</li><li>MCT will ask which keys to use to access the tag (&quot;Map Keys to Sectors&quot;). <ul><li>Select the <code>std.keys</code> file (which should contain <code>FFFFFFFFFFFF</code>, the default key for blank tags).</li><li>Start the mapping/writing process.</li></ul></li><li>Confirm the warning (&quot;Writing to Sector Trailer...&quot;).</li></ol><hr><h2 id="usage-with-boks-sdk" tabindex="-1">Usage with Boks SDK <a class="header-anchor" href="#usage-with-boks-sdk" aria-label="Permalink to &quot;Usage with Boks SDK&quot;">​</a></h2><p>Once your tag is prepared:</p><ol><li>Use the <code>controller.scanNFCTags()</code> method.</li><li>Place your tag on the Boks (blue LED flashes).</li><li>You should receive a <code>NotifyNfcTagFoundPacket</code> notification with the tag&#39;s UID (e.g., <code>A1B2C3D4</code>).</li><li>Use the <code>controller.registerNfcTag()</code> method with this UID to add it to the Boks memory.</li><li>You&#39;re done! Your tag now opens the door.</li></ol>',18)])])}const p=t(r,[["render",s]]);export{g as __pageData,p as default};
